import{_ as s,o as r,c as i,ai as t}from"./chunks/framework.Bke2s2V8.js";const g=JSON.parse('{"title":"Le genre des noms","description":"","frontmatter":{},"headers":[],"relativePath":"module-1-fondations/le-genre-des-noms.md","filePath":"module-1-fondations/le-genre-des-noms.md","lastUpdated":1773302952000}'),a={name:"module-1-fondations/le-genre-des-noms.md"};function d(n,e,l,o,m,u){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="le-genre-des-noms" tabindex="-1">Le genre des noms <a class="header-anchor" href="#le-genre-des-noms" aria-label="Permalink to “Le genre des noms”">​</a></h1><p><strong>Prérequis :</strong> <a href="./alphabet-prononciation.html">Alphabet et prononciation</a></p><p><strong>Objectif :</strong> comprendre le systeme des trois genres en allemand et apprendre les règles et indices qui permettent de les deviner.</p><p>En allemand, chaque nom a un genre : masculin (<em>der</em>), féminin (<em>die</em>) ou neutre (<em>das</em>). Ce genre ne correspond pas toujours au sens du mot, c&#39;est la difficulté principale. Mais il existe des règles qui aident à deviner.</p><h2 id="les-trois-articles" tabindex="-1">Les trois articles <a class="header-anchor" href="#les-trois-articles" aria-label="Permalink to “Les trois articles”">​</a></h2><div class="mt-6 grid grid-cols-3 gap-4"><div class="p-4 rounded-xl border-2 border-blue-200 bg-blue-50 text-center"><div class="text-3xl font-black text-blue-600">der</div><div class="font-semibold text-gray-700 mt-2">Masculin</div><div class="text-sm text-gray-500 mt-1">der Mann (l&#39;homme)<br>der Tisch (la table)<br>der Hund (le chien)</div></div><div class="p-4 rounded-xl border-2 border-red-200 bg-red-50 text-center"><div class="text-3xl font-black text-red-500">die</div><div class="font-semibold text-gray-700 mt-2">Féminin</div><div class="text-sm text-gray-500 mt-1">die Frau (la femme)<br>die Lampe (la lampe)<br>die Blume (la fleur)</div></div><div class="p-4 rounded-xl border-2 border-green-200 bg-green-50 text-center"><div class="text-3xl font-black text-green-600">das</div><div class="font-semibold text-gray-700 mt-2">Neutre</div><div class="text-sm text-gray-500 mt-1">das Kind (l&#39;enfant)<br>das Auto (la voiture)<br>das Buch (le livre)</div></div></div><div class="tip custom-block"><p class="custom-block-title">Toujours apprendre le nom avec son article</p><p>Pas juste <em>Tisch</em> - mais <strong>der Tisch</strong>. L&#39;article fait partie du mot. Apprendre un nom sans son article est une habitude à ne jamais prendre.</p></div><h2 id="regles-utiles-pour-deviner-le-genre" tabindex="-1">Regles utiles pour deviner le genre <a class="header-anchor" href="#regles-utiles-pour-deviner-le-genre" aria-label="Permalink to “Regles utiles pour deviner le genre”">​</a></h2><p>Ces règles ne sont pas absolues, mais elles couvrent une grande partie du vocabulaire.</p><h3 id="terminaisons-generalement-masculines-der" tabindex="-1">Terminaisons généralement masculines (<em>der</em>) <a class="header-anchor" href="#terminaisons-generalement-masculines-der" aria-label="Permalink to “Terminaisons généralement masculines (der)”">​</a></h3><div class="mt-4 grid gap-2"><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-blue-600 w-24 shrink-0">-er (agent)</div><div class="text-sm text-gray-600">Noms formes a partir d&#39;un verbe : <em>der Lehrer</em> (enseignant), <em>der Fahrer</em> (conducteur), <em>der Backer</em> (boulanger)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-blue-600 w-24 shrink-0">-ig / -ich</div><div class="text-sm text-gray-600"><em>der Honig</em> (miel), <em>der Konig</em> (roi), <em>der Teppich</em> (tapis)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-blue-600 w-24 shrink-0">-ling</div><div class="text-sm text-gray-600"><em>der Frühling</em> (printemps), <em>der Lehrling</em> (apprenti)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-blue-600 w-24 shrink-0">-ismus</div><div class="text-sm text-gray-600"><em>der Kapitalismus</em>, <em>der Tourismus</em></div></div></div><p><strong>Par catégorie :</strong> les saisons (<em>der Frühling, der Sommer, der Herbst, der Winter</em>), les jours de la semaine, les mois, les points cardinaux sont masculins.</p><h3 id="terminaisons-generalement-feminines-die" tabindex="-1">Terminaisons généralement feminines (<em>die</em>) <a class="header-anchor" href="#terminaisons-generalement-feminines-die" aria-label="Permalink to “Terminaisons généralement feminines (die)”">​</a></h3><div class="mt-4 grid gap-2"><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-red-500 w-24 shrink-0">-ung</div><div class="text-sm text-gray-600">Regle très fiable : <em>die Zeitung</em> (journal), <em>die Wohnung</em> (appartement), <em>die Lösung</em> (solution)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-red-500 w-24 shrink-0">-heit / -keit</div><div class="text-sm text-gray-600"><em>die Freiheit</em> (liberte), <em>die Schönheit</em> (beaute), <em>die Möglichkeit</em> (possibilité)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-red-500 w-24 shrink-0">-schaft</div><div class="text-sm text-gray-600"><em>die Freundschaft</em> (amitie), <em>die Gesellschaft</em> (societe)</div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-red-500 w-24 shrink-0">-tion / -sion</div><div class="text-sm text-gray-600"><em>die Nation</em>, <em>die Lektion</em>, <em>die Mission</em></div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-red-500 w-24 shrink-0">-in (personne)</div><div class="text-sm text-gray-600"><em>die Lehrerin</em> (professeure), <em>die Ärztin</em> (medecin femme)</div></div></div><h3 id="terminaisons-generalement-neutres-das" tabindex="-1">Terminaisons généralement neutres (<em>das</em>) <a class="header-anchor" href="#terminaisons-generalement-neutres-das" aria-label="Permalink to “Terminaisons généralement neutres (das)”">​</a></h3><div class="mt-4 grid gap-2"><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-green-600 w-24 shrink-0">-chen / -lein</div><div class="text-sm text-gray-600">Regle absolue - les diminutifs sont toujours neutres : <em>das Mädchen</em> (la fille), <em>das Häuschen</em> (la petite maison)</div></div><div class="info custom-block"><p class="custom-block-title">Das Mädchen - la fille est neutre</p><p><em>Mädchen</em> (la fille) est neutre (<em>das</em>) car c&#39;est un diminutif en <em>-chen</em>. La règle du genre grammatical prime sur le sens naturel du mot. C&#39;est un exemple souvent cite qui surprend les débutants.</p></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-green-600 w-24 shrink-0">-ment</div><div class="text-sm text-gray-600"><em>das Instrument</em>, <em>das Dokument</em>, <em>das Experiment</em></div></div><div class="flex items-start gap-3 p-3 rounded-lg border border-gray-200"><div class="font-bold text-green-600 w-24 shrink-0">verbe nominalise</div><div class="text-sm text-gray-600">Un verbe utilisé comme nom est toujours neutre : <em>das Essen</em> (manger / la nourriture), <em>das Lernen</em> (apprendre), <em>das Schreiben</em> (ecrire)</div></div></div><p><strong>Par catégorie :</strong> les couleurs nominalises, les langues (<em>das Deutsche, das Französische</em>), les lettres de l&#39;alphabet sont neutres.</p><h2 id="les-noms-composes" tabindex="-1">Les noms composes <a class="header-anchor" href="#les-noms-composes" aria-label="Permalink to “Les noms composes”">​</a></h2><p>En allemand, on forme facilement des mots composes en concatenant plusieurs noms. Le genre du mot compose est toujours celui du <strong>dernier élément</strong>.</p><ul><li><em>der Flug</em> (vol) + <em>das Zeug</em> (engin) = <strong>das</strong> Flugzeug (avion)</li><li><em>das Haus</em> (maison) + <em>die Tür</em> (porte) = <strong>die</strong> Haustür (porte d&#39;entree)</li><li><em>der Hand</em> + <em>die Tasche</em> (poche, sac) = <strong>die</strong> Handtasche (sac à main)</li></ul><h2 id="au-pluriel-tout-devient-die" tabindex="-1">Au pluriel : tout devient <em>die</em> <a class="header-anchor" href="#au-pluriel-tout-devient-die" aria-label="Permalink to “Au pluriel : tout devient die”">​</a></h2><p>Quel que soit le genre au singulier, l&#39;article au pluriel est toujours <strong>die</strong>.</p><ul><li><em>der Mann</em> → <em>die Männer</em></li><li><em>die Frau</em> → <em>die Frauen</em></li><li><em>das Kind</em> → <em>die Kinder</em></li></ul><div class="tip custom-block"><p class="custom-block-title">Code couleur pour mémoriser</p><p>Utilise des couleurs quand tu notes du vocabulaire : bleu pour <em>der</em>, rouge pour <em>die</em>, vert pour <em>das</em>. Colle des post-its sur les objets chez toi avec l&#39;article et le nom. C&#39;est une des methodes les plus efficaces pour ancrer les genres.</p></div>',24)])])}const p=s(a,[["render",d]]);export{g as __pageData,p as default};
